    "input": "",
    "output": "def search_in_array(arr, item):\n    \"\"\"This function searches for an item in an unsorted array and returns its index.\"\"\"\n    n = len(arr)\n    # Initialize the index\n    index = 0\n    # Iterate over the array\n    while index < n:\n        # If the item is found, return the index \n        if arr[index] == item:\n            return index\n        # Otherwise, go through the next element\n        index += 1\n\n    # If the item is not found, return -1\n    return -1",
