    "instruction": "Create a Windows Forms application in C# for recording time tracking for tasks. The application should have a window to add tasks and a window to view the time spent on each task.",
    "input": "Not applicable",
    "output": "using System;\nusing System.Collections.Generic;\nusing System.Windows.Forms;\n\nnamespace TimeTracker\n{\n public partial class Form1 : Form\n {\n public Form1()\n {\n InitializeComponent();\n }\n \n private void Form1_Load(object sender, EventArgs e)\n {\n LoadTimeTracker();\n }\n \n private void LoadTimeTracker()\n {\n Dictionary<string, TimeSpan> timeTracker = new Dictionary<string, TimeSpan>();\n }\n \n private void addTaskButton_Click(object sender, EventArgs e)\n {\n // Add new task to time tracker\n string taskName = taskNameTextBox.Text;\n \n if (!timeTracker.ContainsKey(taskName))\n {\n timeTracker.Add(taskName, TimeSpan.Zero);\n }\n \n // Refresh list of tasks\n RefreshTaskList();\n }\n \n private void startTimerButton_Click(object sender, EventArgs e)\n {\n // Start timer for selected task\n string taskName = taskListBox.SelectedItem as string;\n \n if (timeTracker.ContainsKey(taskName))\n {\n timeTracker[taskName] = DateTime.Now;\n }\n }\n \n private void endTimerButton_Click(object sender, EventArgs e)\n {\n // End timer for selected task\n string taskName = taskListBox.SelectedItem as string;\n \n if (timeTracker.ContainsKey(taskName))\n {\n TimeSpan timeSpent = DateTime.Now - timeTracker[taskName];\n timeTracker[taskName] = timeSpent;\n \n // Refresh list of tasks\n RefreshTaskList();\n }\n }\n \n private void RefreshTaskList()\n {\n // Refresh list of tasks\n taskListBox.Items.Clear();\n foreach (string taskName in timeTracker.Keys)\n {\n string item = taskName + \": \" + timeTracker[taskName];\n taskListBox.Items.Add(item);\n }\n }\n }\n}",
