    "instruction": "Build a web-crawler to fetch webpages from a given website.",
    "input": "Website URL: https://www.example.com",
    "output": "import requests \nimport urllib.parse \nfrom bs4 import BeautifulSoup \n\n# List to keep track of visited pages \nvisited = []\n\n# Use requests to fetch the webpage \ndef request_webpage(url): \n    try: \n        response = requests.get(url) \n        if response.status_code == 200: \n            # parse the webpage and visit all links recursively \n            soup = BeautifulSoup(response.text, 'html.parser') \n            visit_all_links(soup) \n    except: \n        print('Error accessing the URL') \n\n# visit all the links within the given page\ndef visit_all_links(soup): \n    for link in soup.findAll('a'): \n        href = link.get('href') \n        if href == \"\" or href is None: \n            continue \n        href = urllib.parse.urljoin(url, href) \n        if href not in visited: \n            visited.append(href) \n            print(f\"Visited {href}\") \n            request_webpage(href)\n\n# URL to visit \nurl = \"https://www.example.com/\"\n\n# Visit the given URL \nrequest_webpage(url)",
