    "instruction": "Create a neural network classifier for breast cancer.",
    "input": "",
    "output": "import keras\nfrom keras.models import Sequential\nfrom keras.layers import Dense\n\nclass BreastCancerClassifier(object):\n    \n    def __init__(self, input_dim, output_dim, hidden_layers):\n        self.input_dim = input_dim\n        self.output_dim = output_dim\n        self.hidden_layers = hidden_layers\n        \n        self.model = self.create_model()\n\n    def create_model(self):\n        model = Sequential()\n        # Input layer\n        model.add(Dense(self.input_dim, activation=\"relu\", input_dim=self.input_dim))\n    \n        # Hidden layers\n        for num_neurons in self.hidden_layers:\n            model.add(Dense(num_neurons, activation=\"relu\"))\n\n        # Output layer \n        model.add(Dense(self.output_dim, activation=\"sigmoid\"))\n\n        model.compile(loss=\"binary_crossentropy\",\n            optimizer=\"adam\", metrics=[\"accuracy\"])\n\n        return model",
