    "output": "<svg width=\"900\" height=\"500\">\n\n   //Scales\n    var x = d3.scaleBand()\n    .domain(['China', 'India', 'United States', 'Indonesia', 'Brazil'])\n    .range([0, 900]);\n    \n    var y = d3.scaleLinear()\n    .domain([0, 21.44])\n    .range([500, 0]);\n    \n    //Axes\n    var xAxis = d3.axisBottom(x);\n    var yAxis = d3.axisLeft(y);\n    \n    //Create the SVG\n    var svg = d3.select(\"body\")\n    .append(\"svg\")\n    .attr(\"width\", 900)\n    .attr(\"height\",500);\n    \n    //And now the actual chart\n    svg.selectAll(\"rect\")\n    .data([11.38, 2.72, 21.44, 1.03, 1.86])\n    .enter().append(\"rect\")\n    .attr(\"x\", (d,i) => x(x.domain()[i]))\n    .attr(\"y\", d => y(d))\n    .attr(\"width\", x.bandwidth())\n    .attr(\"height\", d => 500 - y(d))\n    .style(\"fill\", 'steelblue');\n    \n    //Tooltips\n    svg.selectAll(\"rect\")\n    .on(\"mouseover\", function(d, i) {\n        d3.select(this)\n        .style(\"fill\", '#FFFF00');\n    })\n    .on(\"mouseout\", function(d, i) {\n        d3.select(this)\n        .style(\"fill\", 'steelblue')\n    }); \n    \n    //Axes\n    svg.append(\"g\")\n  .attr(\"class\", \"x axis\")\n  .attr(\"transform\", \"translate(0,\" + 500 + \")\")\n  .call(xAxis)\n  .selectAll(\"text\")\n  .style(\"text-anchor\", \"end\")\n  .attr(\"dx\", \"-.8em\")\n  .attr(\"dy\", \".15em\")\n  .attr(\"transform\", \"rotate(-65)\");\n\nsvg.append(\"g\")\n  .attr(\"class\", \"y axis\")\n  .attr(\"transform\", \"translate(0,0)\")\n  .call(yAxis);\n\n</svg>",
