    "input": "Number 1 = 2, Number 2 = 3",
    "output": "// C++ program to find LCM of two given numbers\n#include<bits/stdc++.h> \nusing namespace std; \n\nint findLCM(int n1, int n2) \n{ \n\t// maximum number between n1 and n2 is stored in max\n\tint max = (n1 > n2) ? n1 : n2; \n\n\tint i = max; \n\t\n\t// Always true \n\twhile(1) \n\t{ \n\t\tif( i % n1 == 0 && i % n2 == 0 ) \n\t\t{ \n\t\t\treturn i; \n\t\t} \n\t\ti += max; \n\t} \n} \n\n// Driver program \nint main() \n{ \n\tint n1 = 2, n2 = 3; \n\tcout<<\"LCM of \"<<n1<<\" and \"<<n2<<\" is \"<<findLCM(n1, n2); \n\treturn 0; \n}",
