    "input": "string = \"Hello World\"",
    "output": "def rot13(string):\n    output = \"\"\n    for char in string:\n        if char == \" \":\n            output += char\n            continue\n        ascii_code = ord(char)\n        if ascii_code >= 97 and ascii_code <= 122:\n            if ascii_code <= 109:\n                ascii_code += 13\n            else:\n                ascii_code -= 13\n        else:\n            if ascii_code <= 77:\n                ascii_code += 13\n            else:\n                ascii_code -= 13\n        output += chr(ascii_code)\n    return output",
    "category": "code_instruction"
