    "instruction": "Create a program to compare the similarities between two supplied strings.",
    "input": "str1= \"I love eating Pizza\"\nstr2= \"I enjoy eating pasta\"",
    "output": "\"\"\"\nCompare the similarities between two strings\n\"\"\"\n\ndef compare_strings(str1, str2):\n    # Split strings into a list of words\n    str1_list = str1.split()\n    str2_list = str2.split()\n\n    # Create an empty set for common words\n    common_words = set()\n\n    # Iterate over the words in either string\n    for word1 in str1_list:\n        for word2 in str2_list:\n            if word1 == word2:\n                common_words.add(word1)\n\n    # Calculate the number of words in common\n    num_common_words = len(common_words)\n\n    # Calculate the total number of words\n    total_words = len(str1_list) + len(str2_list)\n\n    # Calculate the similarity as a percentage\n    similarity = (num_common_words/total_words)*100\n\n    return similarity\n    \nif __name__ == '__main__':\n    str1 = \"I love eating Pizza\"\n    str2 = \"I enjoy eating pasta\"\n    similarity = compare_strings(str1,str2)\n    print(similarity)",
