    "instruction": "Write a PHP script that takes a string as input and outputs an array or strings with all possible combinations of characters.",
    "input": "abc",
    "output": "<?php\n$str = \"abc\";\n \nfunction permutation($str) {\n\t$length = strlen($str);\n\tif ($length == 1) {\n\t\treturn [$str];\n\t}\n\t\n\t$perm = permutation(substr($str, 1));\n\t$first = substr($str, 0, 1);\n\t$result = array();\n\n\tforeach ($perm as $p) {\n\t\t$size = strlen($p);\n\t\tfor ($i = 0; $i <= $size; $i++) {\n\t\t\t$s = substr($p, 0, $i) . $first . substr($p, $i);\n\t\t\t$result[] = $s;\n\t\t}\n\t}\n \n\treturn $result;\n}\n \nprint_r(permutation($str));\n\n# Output\nArray\n(\n [0] => abc\n [1] => acb\n [2] => bac\n [3] => bca\n [4] => cab\n [5] => cba\n)",
