    "instruction": "Create a C++ program to construct a linked list with insert and delete operations.",
    "input": "Not applicable",
    "output": "#include<iostream>\n\nusing namespace std;\n\nstruct node\n{\n    int data;\n    node *next;\n};\n\nclass list \n{\n    private:\n    node *head, *tail;\n    public:\n    list()\n    {\n        head=NULL;\n        tail=NULL;\n    }\n  \n    void insert(int element) \n    {\n        node *temp=new node;\n        temp->data=element;\n        temp->next=NULL;\n        if(head==NULL)\n        {\n            head=temp;\n            tail=temp;\n            temp=NULL;\n        }\n        else\n        {\t\n            tail->next=temp;\n            tail=temp;\n        }\n    }\n  \n    void delete_element(int element)\n    {\n    \tnode *previous, *current;\n    \tcurrent=head;\n    \twhile(current!=NULL)\n    \t{\n            if(current->data==element)\n    \t    {\n    \t        if(current==head)\n    \t        {\n    \t\t        head=head->next;\n    \t\t        delete current;\n    \t\t        cout<<element<<\" deleted from the list\"<<endl;\n    \t        }\t\t\n    \t        else\n    \t        {\n    \t\t        previous->next=current->next;\n    \t\t        delete current;\n    \t        }\n            }\n            previous=current;\n            current=current->next;\n        }\n    }\n    void display()\n    {\n        node *temp=new node;\n        temp=head;\n        while(temp!=NULL)\n        {\n            cout<<temp->data<<\"\\t\";\n            temp=temp->next;\n        }\n\tcout<<endl;\n    }\n};\n\nint main()\n{\n    list l;\n    l.insert(1);\n    l.insert(2);\n    l.insert(3);\n    l.display();\n    l.delete_element(2);\n    l.display();\n    return 0;\n}",
    "category": "code_instruction"
