    "instruction": "Create an interactive bank calculator that calculates interest and compouned interest.",
    "input": "",
    "output": "import tkinter\n\n# initialise a tkinter window\nwindow = tkinter.Tk()\nwindow.title(\"Bank Calculator\")\n\n# define functions\ndef calculate_interest():\n    # get user inputs\n    amount = float(amount_entry.get())\n    rate = float(rate_entry.get())\n    years = int(years_entry.get())\n    simple_interest = amount * rate * years\n    compounding_interest = amount * (1 + rate/12) ** (12 * years)\n    \n    # output results \n    simple_interest_label.config(text='Simple Interest = $' + str(simple_interest))\n    compound_interest_label.config(text='Compound Interest = $' + str(compounding_interest))\n   \n# view\namount_label = tkinter.Label(window, text=\"Amount\")\namount_entry = tkinter.Entry(window)\nrate_label = tkinter.Label(window, text=\"Rate (%)\")\nrate_entry = tkinter.Entry(window)\nyears_label = tkinter.Label(window, text=\"Years\")\nyears_entry = tkinter.Entry(window)\ncalculate_button = tkinter.Button(window, text=\"Calculate\", command=calculate_interest)\nsimple_interest_label = tkinter.Label(window)\ncompound_interest_label = tkinter.Label(window)\n\n# layouts\namount_label.grid(row=1, column=1)\namount_entry.grid(row=1, column=2)\nrate_label.grid(row=2, column=1)\nrate_entry.grid(row=2, column=2)\nyears_label.grid(row=3, column=1)\nyears_entry.grid(row=3, column=2)\ncalculate_button.grid(row=4, column=2)\nsimple_interest_label.grid(row=5, column=2)\ncompound_interest_label.grid(row=6, column=2)\n\n# event loop\nwindow.mainloop()",
