    "output": "using System;\nusing System.Collections.Generic;\n\nclass Primes\n{\n    public static List<int> GetPrimes() {\n        List<int> primes = new List<int>();\n        int num = 2;\n        \n        while (primes.Count < 25) {\n            if (IsPrime(num))\n                primes.Add(num);\n            \n            num++;\n        }\n        \n        return primes;\n    }\n    \n    public static bool IsPrime(int num) {\n        for (int i = 2; i < num; i++) {\n            if (num % i == 0)\n                return false;\n        }\n        return true;\n    }\n}\n\nclass Program\n{\n    public static void Main(string[] args) {\n        Console.WriteLine(string.Join(\", \", Primes.GetPrimes()));\n    }\n}",
