    "output": "// Express app\nconst express = require('express');\nconst app = express();\n\n// Body parser\napp.use(express.json());\n\n// Routes\nconst todosRoutes = require('./routes/todos');\napp.use('/todos', todosRoutes);\n\n// Start the server\nconst port = process.env.PORT || 5000;\napp.listen(port, () => console.log(`Server started on port ${port}`));\n\n// Todo list React component\nimport React, { useState } from 'react';\nconst TodoList = () => {\n const [todos, setTodos] = useState([]);\n\n const addTodo = todo => {\n setTodos([...todos, todo]);\n };\n\n const deleteTodo = index => {\n setTodos(todos.filter((todo, i) => i !== index));\n };\n\n const editTodo = (index, todo) => {\n let updatedTodos = [...todos];\n updatedTodos[index] = todo;\n setTodos(updatedTodos);\n };\n\n return (\n <div className=\"TodoList\">\n <h1>Todo List</h1>\n <ul>\n {todos.map((todo, i) => (\n <li key={i}>\n <TodoForm\n todo={todo}\n deleteTodo={() => deleteTodo(i)}\n updateTodo={todo => editTodo(i, todo)}\n />\n </li>\n ))}\n </ul>\n <TodoForm addTodo={addTodo} />\n </div>\n );\n};\n\nconst TodoForm = ({ todo, addTodo, deleteTodo, updateTodo }) => (\n <form>\n <input\n type=\"text\"\n value={todo.description}\n placeholder=\"Add todo\"\n onChange={e => updateTodo({ description: e.target.value })}\n />\n {todo.description && (\n <button type=\"button\" onClick={deleteTodo}>\n X\n </button>\n )}\n {!todo.description && (\n <button type=\"submit\" onClick={addTodo}>\n Add\n </button>\n )}\n </form>\n);\n\nexport default TodoList;",
