    "output": "public void sort(int[] arr) {\n  for (int i = 0; i < arr.length; i++) {\n        int minIdx = i;\n        for (int j = i+1; j < arr.length; j++) {\n            if (arr[j] < arr[minIdx]) {\n                minIdx = j;\n            }\n        }\n\n        int temp = arr[i];\n        arr[i] = arr[minIdx];\n        arr[minIdx] = temp;\n    }\n}",
