    "output": "// TodoListActivity.java\n\npublic class TodoListActivity extends Activity {\n private ArrayList<Task> tasks;\n private ListView listView;\n \n @Override\n protected void onCreate(Bundle savedInstanceState) {\n super.onCreate(savedInstanceState);\n \n tasks = new ArrayList<>();\n listView = findViewById(R.id.list_view);\n \n listView.setAdapter(new TaskAdapter(tasks));\n // On item click listener\n listView.setOnItemClickListener(new AdapterView.OnItemClickListener() {\n @Override\n public void onItemClick(AdapterView<?> parent, View view, int position,\n   long id) {\n   //Edit or delete the task\n  }\n });\n \n  // Add button to add new tasks\n Button addButton = findViewById(R.id.add_task);\n addButton.setOnClickListener(new View.OnClickListener() {\n @Override\n public void onClick(View v) {\n // Show add task dialog\n showAddTaskDialog();\n  }\n });\n}\n\nprivate void showAddTaskDialog() {\n // Use AlertDialog.Builder to create the dialog\n AlertDialog.Builder dialogBuilder = new AlertDialog.Builder(this);\n\n // Inflate the layout\n LayoutInflater inflater = this.getLayoutInflater();\n final View dialogView = inflater.inflate(R.layout.add_task_dialog, null);\n dialogBuilder.setView(dialogView);\n \n // Add action buttons\n dialogBuilder.setPositiveButton(\"Add\", new DialogInterface.OnClickListener() {\n @Override\n public void onClick(DialogInterface dialog, int which) {\n   // Get the task name and time limit from the dialog box\n   EditText taskNameEditText = dialogView.findViewById(R.id.task_name);\n   EditText timeLimitEditText = dialogView.findViewById(R.id.time_limit);\n   \n   // Create Task object and add it to the list of tasks\n   Task task = new Task(taskNameEditText.getText().toString(),\n    Integer.parseInt(timeLimitEditText.getText().toString()));\n   tasks.add(task);\n  \n  // Notify the adapter\n  ((BaseAdapter) listView.getAdapter()).notifyDataSetChanged();\n  }\n });\n \n dialogBuilder.setNegativeButton(\"Cancel\", null);\n \n dialogBuilder.create().show();\n }\n\npublic class Task {\n  private String name;\n  private int timeLimit;\n  \n  public Task(String name, int timeLimit) {\n    this.name = name;\n    this.timeLimit = timeLimit;\n  }\n  \n  // Getters and setters\n}",
