    "output": "outliers_identifier <- function(data) \n{\n   outlier_list <- c()\n   quartiles <- quantile(data, c(0.25, 0.75))\n   lower_whisker <- quartiles[1] - 1.5 * IQR(data)\n   upper_whisker <- quartiles[2] + 1.5 * IQR(data)\n   for(i in 1:length(data)){\n     if(data[i]< lower_whisker || data[i] > upper_whisker){\n       outlier_list <- c(outlier_list, data[i])\n     }\n   }\n   return(outlier_list)\n }",
