    "output": "public class Fibonacci {\n    \n    public static void main(String[] args) {\n        System.out.println(fibonacci(10));\n    }\n    \n    public static int fibonacci(int n){\n        if(n == 0 || n == 1){\n            return 1;\n        }\n        \n        int prevPrev = 1;\n        int prev = 1;\n        int current = 0;\n        \n        for(int i = 2; i <= n; i++){\n            current = prev + prevPrev;\n            prevPrev = prev;\n            prev = current;\n        }\n        \n        return current;\n    }\n}",
