    "input": "Not applicable",
    "output": "public class Queue {\n\n private int[] arr;\n private int length;\n private int first;\n private int last;\n\n public Queue(int size) {\n  arr = new int[size];\n  length = 0;\n  first = 0;\n  last = -1;\n }\n\n public void enqueue(int n) {\n  if (length == arr.length) {\n   System.out.println(\"Queue is full!\");\n   return;\n  }\n  last = (last + 1) % arr.length;\n  arr[last] = n;\n  length++;\n }\n\n public int dequeue() {\n  if (length == 0) {\n   System.out.println(\"Queue is empty!\");\n   return -1;\n  }\n  int value = arr[first];\n  arr[first] = 0;\n  first = (first + 1) % arr.length;\n  length--;\n  return value;\n }\n}",
