    "output": "public static boolean isAnagram(String s, String t) {\n    // If the string lengths are different, return False.\n    if (s.length() != t.length()) {\n        return false;\n    }\n\n    // Create integers arrays for character counts for both strings\n    int[] sCount = new int[26];\n    int[] tCount = new int[26];\n    for (int i = 0; i < s.length(); i++) {\n        sCount[s.charAt(i) - 'a'] += 1;\n        tCount[t.charAt(i) - 'a'] += 1;\n    }\n    // Compare the character count arrays.\n    for (int i = 0; i < 26; i++) {\n        if (sCount[i] != tCount[i]) {\n            return false;\n        }\n    }\n    return true;\n}",
