    "output": "\"\"\"\nWrite a program to merge two sorted lists of integers\n\"\"\"\n\ndef merge_lists(l1, l2):\n    merged = []\n    i, j = 0, 0\n    while i < len(l1) and j < len(l2):\n        if l1[i] < l2[j]:\n            merged.append(l1[i])\n            i += 1\n        else:\n            merged.append(l2[j])\n            j += 1\n    merged += l1[i:] + l2[j:]\n    return merged\n\nif __name__ == '__main__':\n    l1 = [1, 3, 5, 7]\n    l2 = [2, 4, 6, 8]\n    print(merge_lists(l1, l2)) # [1, 2, 3, 4, 5, 6, 7, 8]",
