    "output": "\"\"\"\nCreate a program to detect and highlight potential typos in a sentence.\n\nInput:\nInput sentence: \"Thhis sentennce conntains somme typoos\".\n\nOutput:\nCreate a function `detect_typos()` that takes a string as input and returns a string with the potential typos highlighted.\n\ndef detect_typos(sentence):\n    results = []\n    words = sentence.split(' ')\n    \n    for word in words:\n        # Compare each letter with the previous letter in the word \n        for i in range(1, len(word)):\n            if word[i] == word[i-1]:\n                word = word[:i] + '<typo>' + word[i] + '</typo>' + word[i+1:]\n                \n        results.append(word)\n    \n    return ' '.join(results)\n\nif __name__ == '__main__':\n    sentence = 'Thhis sentennce conntains somme typos'\n    print(detect_typos(sentence))\n\"\"\"",
