    "input": "message = \"Hello World\"",
    "output": "\"\"\"\nAdapt the code to encrypt a given string using Caesar Cipher\n\"\"\"\n\ndef Caesar_cipher(message, key):\n    # Initialize the output string \n    output_string = \"\" \n  \n    # Loop through each character in the message\n    for i in range(len(message)):\n        char = message[i]\n        # If the character is a letter, shift it according to the key\n        if (char.isalpha()): \n            if  (char.isupper()):\n                output_string += chr((ord(char) + key - 65) % 26 + 65) \n            else: \n                output_string += chr((ord(char) + key - 97) % 26 + 97) \n        # Else, keep the character as it is\n        else: \n            output_string += char\n    return output_string \n\nif __name__ == \"__main__\":\n    message = \"Hello World\"\n    key = 4\n    print(Caesar_cipher(message, key))",
