    "input": "String: \"ABC\"",
    "output": "def permutations(string):\n    if len(string) == 1: \n        return string\n    else: \n        perm_list = []\n        for i in string: \n            for perm in permutations(string.replace(i, '', 1)): \n                perm_list.append(i + perm) \n    return perm_list  \n\nstring = \"ABC\"\nresult = permutations(string)\nprint(result)",
