    "output": "// Java program to find pairs with given sum in an array\npublic class FindPairSum {\n   public static void main(String[] args) {\n      //array of numbers\n      int [] numbers = {2, 4, 3, 5, 7, 8, 9};\n      //given sum\n      int sum = 7;\n\n      //map to store numbers and their index\n      Map<Integer, Integer> indexMap = new HashMap<Integer, Integer>();\n\n      //traverse through array \n      for (int i = 0; i < numbers.length; i++) {\n         //find the complement for current element\n         int complement = sum - numbers[i];\n\n         //check if the complement exists in array\n         if (indexMap.containsKey(complement)) {\n            //print if pair is found\n            System.out.println(\"Pair found at index \" +  indexMap.get(complement) + \" and \" + i);\n         }\n         //add current number and its index\n         indexMap.put(numbers[i], i);\n      }\n   }\n}",
