    "output": "// Function to compress an integer using bitwise operations\nconst compress = (x) => {\n    const mask = 0x3\n    let compressed = 0\n    let count = 0\n    while (x != 0) {\n        const b1 = (x & mask) << (count * 2)\n        compressed |= b1\n        x >>= 2\n        count++\n    }\n    return compressed\n}\n\n// Input\nlet x = 30;\n\n// Output\nlet compressedVal = compress(x);\nconsole.log(compressedVal);",
