    "instruction": "Create a Node.js application with a REST API for managing a blog. This API should include endpoints for creating a new post, updating an existing post, deleting a post, listing all posts, and getting a single post.",
    "input": "Not applicable",
    "output": "const express = require('express');\nconst bodyParser = require('body-parser');\nconst axios = require('axios');\n\nconst app = express();\napp.use(bodyParser.urlencoded({ extended: true }));\n\napp.post('/posts', (req, res) => {\n const { title, content } = req.body;\n\n axios.post('https://myblog.com/api/posts', { title, content })\n .then(response => {\n const postId = response.data;\n res.status(200).json({ postId });\n })\n .catch(err => {\n console.error(err);\n res.status(500).json({ error: 'Failed to create post' });\n });\n});\n\napp.get('/posts', (req, res) => {\n axios.get('https://myblog.com/api/posts')\n .then(response => {\n const posts = response.data;\n res.status(200).json(posts);\n })\n .catch(err => {\n console.error(err);\n res.status(500).json({ error: 'Failed to get posts' });\n });\n});\n\napp.get('/posts/:postId', (req, res) => {\n axios.get(`https://myblog.com/api/posts/${req.params.postId}`)\n .then(response => {\n const post = response.data;\n res.status(200).json(post);\n })\n .catch(err => {\n console.error(err);\n res.status(500).json({ error: 'Failed to get post' });\n });\n});\n\napp.put('/posts/:postId', (req, res) => {\n const { title, content } = req.body;\n\n axios.put(`https://myblog.com/api/posts/${req.params.postId}`, { title, content })\n .then(response => {\n res.status(200).json({ message: 'Post updated' });\n })\n .catch(err => {\n console.error(err);\n res.status(500).json({ error: 'Failed to update post' });\n });\n});\n\napp.delete('/posts/:postId', (req, res) => {\n axios.delete(`https://myblog.com/api/posts/${req.params.postId}`)\n .then(response => {\n res.status(200).json({ message: 'Post deleted' });\n })\n .catch(err => {\n console.error(err);\n res.status(500).json({ error: 'Failed to delete post' });\n });\n});\n\napp.listen(8080, () => {\n console.log('Blog API running on port 8080');\n});",
