    "output": "def longestCommonPrefix(stringArray):\n    if len(stringArray) == 0:\n        return \"\"\n    minString = min(stringArray, key=len)\n    for i in range(1, len(minString) + 1):\n        substring = minString[:i]\n        for j in range(1, len(stringArray)):\n            if stringArray[j].find(substring) != 0:\n                return minString[:i-1]\n    return minString\n\narray = [\"apple\", \"app\", \"application\", \"appliance\"]\nprint(longestCommonPrefix(array))",
