    "instruction": "Construct an AI agent that plays the Connect Four game",
    "input": "Not applicable",
    "output": "class ConnectFourAgent():\n def __init__(self, board):\n  self.board = board\n \n def make_move(self):\n  best_score = -1000\n  best_move = None\n\n  for col in range(self.board.width):\n   row = 0\n   while row < self.board.height and self.board.grid[row][col] == '.':\n    row += 1\n  \n   tmp_board = copy.deepcopy(self.board)\n   tmp_board.add_piece(row - 1, col, self.piece) \n   score = self.minmax(tmp_board, depth-1, False) \n   if score > best_score:\n    best_score = score \n    best_move = col\n  \n  self.board.add_piece(row - 1, best_move, self.piece)\n\n @staticmethod\n def minmax(board, depth, isMaximizing):\n  if board.check_win():\n    if board.current_turn == self.piece:\n     return 1 # Win\n    else:\n     return -1 # Loss\n \n  if depth == 0:\n   return 0\n \n  best_score = -1000 if isMaximizing else 1000\n  for col in range(board.width):\n   row = 0\n   while row < board.height and board.grid[row][col] == '.':\n    row += 1\n  \n   tmp_board = copy.deepcopy(board)\n   tmp_board.add_piece(row - 1, col, board.current_turn) \n   score = self.minmax(tmp_board, depth-1, not isMaximizing) \n   if isMaximizing:\n    best_score = max(score, best_score)\n   else: \n    best_score = min(score, best_score) \n \n  return best_score",
