    "instruction": "Please generate an efficient solution to evaluate a given prefix expression.",
    "input": "",
    "output": "def evaluate_expression(exp):\n    stack = []\n    for token in exp:\n        if isinstance(token, int):\n            stack.append(token)\n        else:\n            op2, op1 = stack.pop(), stack.pop()\n            if token == '+':\n                stack.append(op1 + op2)\n            elif token == '-':\n                stack.append(op1 - op2)\n            elif token == '*':\n                stack.append(op1 * op2)\n            elif token == '/':\n                stack.append(op1 / op2)\n\n    return stack.pop()",
