    "output": "def max_unique_substrings(my_string):\n    n = len(my_string)\n    max_substrings = 0\n    for i in range(n):\n        for j in range(i+1, n + 1):\n            substring = my_string[i:j]\n            if substring == ''.join(set(substring)):\n                max_substrings += 1    \n    return max_substrings",
