    "input": "(5,5), (7,7), (0,2)",
    "output": "import java.util.Arrays;\n\nclass ClosestPoints {\n\n    public static int findClosestPoints(int[][] points) {\n\n        int minDistance = Integer.MAX_VALUE;\n        for(int i=0; i<points.length; i++) {\n            for(int j=i+1; j<points.length; j++) {\n                int distance = (int)Math.hypot(points[i][0] - points[j][0], \n                    points[i][1] - points[j][1]);\n                if(distance < minDistance)\n                    minDistance = distance;\n            }\n        }\n        return minDistance;\n    }\n\n    public static void main(String[] args) {\n        int [][]points = {{5,5}, {7,7}, {0,2}};\n        System.out.println(\"The closest points are \" \n            + findClosestPoints(points)); \n    } \n}",
