    "output": "import javax.swing.*; \nimport java.awt.*; \nimport java.awt.event.*; \n  \npublic class SwingExample { \n    private JFrame mainFrame; \n    private JLabel headerLabel; \n    private JLabel statusLabel; \n    private JPanel controlPanel; \n    private boolean lightSwitchState = false;\n  \n    public SwingExample(){ \n        prepareGUI(); \n    } \n\n    public static void main(String[] args){ \n        SwingExample swingExample = new SwingExample();      \n        swingExample.showButtonPressed(); \n    } \n\n    private void prepareGUI(){ \n        mainFrame = new JFrame(\"Java Swing Examples\"); \n        mainFrame.setSize(400,400); \n        mainFrame.setLayout(new GridLayout(3, 1)); \n        mainFrame.addWindowListener(new WindowAdapter() { \n            public void windowClosing(WindowEvent windowEvent){ \n               System.exit(0); \n            } \n         }); \n  \n         headerLabel = new JLabel(\"\", JLabel.CENTER);        \n         statusLabel = new JLabel(\"\",JLabel.CENTER);    \n\n         statusLabel.setSize(350,100); \n \n         controlPanel = new JPanel(); \n         controlPanel.setLayout(new FlowLayout()); \n\n         mainFrame.add(headerLabel); \n         mainFrame.add(controlPanel); \n         mainFrame.add(statusLabel); \n         mainFrame.setVisible(true); \n    } \n \n    private void showButtonPressed(){ \n        headerLabel.setText(\"Control in action: Button\"); \n \n        JButton switchButton = new JButton(\"Toggle Lightswitch\"); \n        switchButton.setActionCommand(\"Toggle Lightswitch\"); \n        switchButton.addActionListener(new ButtonClickListener()); \n        switchButton.setSize(30, 50);\n        controlPanel.add(switchButton); \n \n        mainFrame.setVisible(true); \n    } \n \n    private class ButtonClickListener implements ActionListener{ \n        public void actionPerformed(ActionEvent e) { \n            lightSwitchState = !lightSwitchState; \n            statusLabel.setText(\"Lightswitch is: \" + \n                    (lightSwitchState ? \"ON\" : \"OFF\"));\n        } \n    } \n}",
