    "instruction": "Please provide a program to empty a given stack using recursion.",
    "input": "",
    "output": "class Stack: \n   \n    def __init__(self): \n        self.stack = [] \n       \n    def isEmpty(self): \n        return len(self.stack) == 0\n   \n    def push(self, data): \n        self.stack.append(data) \n           \n    def pop(self): \n        if self.isEmpty(): \n            return \"Underflow\"\n        else: \n            return self.stack.pop() \n           \n    def emptyStack(self): \n        self.stack = [] \n        print(\"Stack is empty\") \n       \n    def emptyStackUsingRecursion(self): \n        if self.isEmpty(): \n            return\n        else: \n            self.pop() \n            self.emptyStackUsingRecursion() \n           \ns1 = Stack() \ns1.push(1) \ns1.push(2) \ns1.push(3) \ns1.push(4) \nprint(s1.pop()) \ns1.emptyStackUsingRecursion() \nprint(s1.pop())",
