    "input": "Not applicable",
    "output": "public class MainActivity extends AppCompatActivity {\n \n private RecyclerView groceryListView;\n private GroceryListAdapter adapter;\n private List<String> groceryListItems = new ArrayList<>();\n \n @Override\n public void onCreate(Bundle savedInstanceState) {\n  super.onCreate(savedInstanceState);\n  setContentView(R.layout.activity_main);\n \n  // Setup the list view\n  groceryListView = findViewById(R.id.groceryListView);\n  groceryListView.setLayoutManager(new LinearLayoutManager(this));\n  adapter = new GroceryListAdapter(groceryListItems);\n  groceryListView.setAdapter(adapter);\n \n  // Add items\n  findViewById(R.id.addBtn).setOnClickListener(v -> {\n   String item = ((EditText)findViewById(R.id.itemField)).getText().toString();\n   if (!groceryListItems.contains(item)) {\n    groceryListItems.add(item);\n    adapter.notifyDataSetChanged();\n   }\n  });\n \n  // Delete items\n  findViewById(R.id.deleteBtn).setOnClickListener(v -> {\n   String item = ((EditText)findViewById(R.id.itemField)).getText().toString();\n   if (groceryListItems.contains(item)) {\n    groceryListItems.remove(item);\n    adapter.notifyDataSetChanged();\n   }\n  });\n }\n \n // Adapter class for the grocery list view\n private class GroceryListAdapter extends RecyclerView.Adapter<GroceryListAdapter.ViewHolder> {\n \n  private List<String> items;\n \n  GroceryListAdapter(List<String> items) {\n   this.items = items;\n  }\n \n  @Override\n  public ViewHolder onCreateViewHolder(ViewGroup parent, int viewType) {\n   LayoutInflater inflater = LayoutInflater.from(parent.getContext());\n   View view = inflater.inflate(R.layout.list_view_item, parent, false);\n   return new ViewHolder(view);\n  }\n \n  @Override\n  public void onBindViewHolder(ViewHolder holder, int position) {\n   holder.itemName.setText(items.get(position));\n  }\n \n  @Override\n  public int getItemCount() {\n   return items.size();\n  }\n \n  public class ViewHolder extends RecyclerView.ViewHolder {\n   TextView itemName;\n \n   ViewHolder(View itemView) {\n    super(itemView);\n    itemName = itemView.findViewById(R.id.itemName);\n   }\n  }\n }\n}",
