    "instruction": "Generate code to find the index of a given element in a given sorted array.",
    "input": "array = [1, 5, 10, 18, 33]\nelement = 10",
    "output": "def find_index(array, element):\n    \"\"\"Function to find the index of a given element in a given sorted array\"\"\"\n    low_index = 0\n    high_index = len(array) - 1\n    found = False\n    while low_index <= high_index and not found:\n        mid_index = int((low_index + high_index) / 2)\n        if array[mid_index] == element:\n            found = True\n            return mid_index\n        elif array[mid_index] > element:\n            high_index = mid_index - 1\n        else:\n            low_index = mid_index + 1\n    return -1",
