    "input": "[5, 4, 3, 2, 1]",
    "output": "def quick_sort(nums):\n    if len(nums) <= 1:\n        return nums\n    else:\n        q = random.choice(nums)\n        s_nums = []\n        m_nums = []\n        e_nums = []\n        for n in nums:\n            if n < q:\n                s_nums.append(n)\n            elif n > q:\n                m_nums.append(n)\n            else:\n                e_nums.append(n)\n        return quick_sort(s_nums) + e_nums + quick_sort(m_nums)\n\nsorted_nums = quick_sort([5, 4, 3, 2, 1])\nprint(sorted_nums)",
