    "output": "def frequencyCounter(text):\n    words = text.split()\n    counter = {}\n\n    for word in words:\n        if word not in counter:\n            counter[word] = 0\n\n        counter[word] += 1\n\n    return counter\n\ntext = \"Today was a good day. It was raining outside, but I felt happy.\"\n\nprint(frequencyCounter(text))",
