    "input": "[ apple, orange, apple, grapes, banana, apple]",
    "output": "def mostFrequentItem(arr):\n    # create an empty dictionary\n    freq_dict = {}\n \n    # loop through list and count frequency\n    for item in arr:\n        if item in freq_dict: \n            freq_dict[item] += 1\n        else: \n            freq_dict[item] = 1\n    \n    # get maximum frequency\n    maximum_freq = max(freq_dict.values()) \n \n    # loop through dict and find key with maximum frequency\n    for key, value in freq_dict.items(): \n        if value == maximum_freq: \n            max_freq_item = key\n    \n    return max_freq_item",
