    "input": "A = [1, -3, 2, 5, -4, 7]",
    "output": "def max_subarray_sum(A):\n    # Declare a variable to hold the current sum\n    curr_sum = 0\n    # Declare a variable to hold the maximum sum\n    max_sum = 0\n    # Iterate through the elements of the array\n    for num in A:\n        # Find the current sum\n        curr_sum = max(curr_sum + num, num)\n        # Update the maximum sum, if it is bigger\n        max_sum = max(max_sum, curr_sum)\n    # Return the maximum sum\n    return max_sum",
