    "output": "def longestCommonSubstring(str1, str2):\n    max_len = 0\n    temp_str = \"\" \n    \n    # Create a 2-D list \n    matrix = [[0 for i in range(len(str1))] for j in range(len(str2))] \n\n    for i in range(len(str1)): \n        for j in range(len(str2)): \n            if str1[i] == str2[j]: \n                if i == 0 or j == 0: \n                    matrix[i][j] = 1\n                else:  \n                    matrix[i][j] = matrix[i - 1][j - 1] + 1\n                if matrix[i][j] > max_len: \n                    max_len = matrix[i][j] \n                    temp_str = str1[i - max_len + 1: i + 1] \n    return temp_str",
