    "input": "[5, 3, 2, 4, 1]",
    "output": "\"\"\"\nWrite a function which takes a list and sorts it using the Bubble Sort algorithm.\n\"\"\"\n\ndef bubble_sort(lst):\n    # Iterate over the list\n    for i in range(len(lst)-1):\n        # Iterate over each element of the list\n        for j in range(0, len(lst)-i-1):\n            # if the current element is greater than the next element in the list, swap them\n            if lst[j] > lst[j+1] :\n                lst[j], lst[j+1] = lst[j+1], lst[j]\n\nif __name__ == '__main__':\n    lst = [5, 3, 2, 4, 1]\n    bubble_sort(lst)\n    print(lst)",
