    "output": "class Node {\n  constructor(data) {\n    this.data = data\n    this.next = null\n  }\n}\n\nclass LinkedList {\n  constructor() {\n    this.head = null\n    this.size = 0\n  }\n\n  // add node to the List\n  add(data) {\n    // create a new node\n    let node = new Node(data)\n    let current\n\n    // if list is empty assign node to head\n    if (this.head == null) {\n      this.head = node\n    } else {\n      current = this.head\n\n      while (current.next) {\n        current = current.next\n      }\n\n      current.next = node\n    }\n    this.size++;\n  }\n}",
