    "output": "import React from \"react\";\nimport { View, Text, StyleSheet, FlatList } from \"react-native\";\n\nconst contacts = [\n  { name: \"John Doe\", email: \"john@example.com\" },\n  { name: \"Jane Doe\", email: \"jane@example.com\" },\n  { name: \"Steve Smith\", email: \"steve@example.com\" },\n];\n\nclass ContactList extends React.Component {\n  state = {\n    contacts: contacts,\n  };\n\n  addContact = (name, email) => {\n    contacts.push({ name, email });\n    this.setState({ contacts });\n  };\n\n  editContact = (name, email, index) => {\n    contacts[index] = { name, email };\n    this.setState({ contacts });\n  };\n\n  deleteContact = (index) => {\n    contacts.splice(index, 1);\n    this.setState({ contacts });\n  };\n\n  render() {\n    return (\n      <View style={styles.container}>\n        <View style={styles.header}>\n          <Text style={styles.title}>Contacts List</Text>\n        </View>\n        <FlatList\n          data={this.state.contacts}\n          renderItem={({ item, index }) => {\n            return (\n              <View style={styles.listItem}>\n                <Text>Name: {item.name}</Text>\n                <Text>Email: {item.email}</Text>\n                <View style={styles.buttonContainer}>\n                  <button\n                    style={styles.button}\n                    onPress={() => {\n                      this.editContact(item.name, item.email, index);\n                    }}\n                  >\n                    Edit\n                  </button>\n                  <button\n                    style={styles.button}\n                    onPress={() => {\n                      this.deleteContact(index);\n                    }}\n                  >\n                    Delete\n                  </button>\n                </View>\n              </View>\n            );\n          }}\n          keyExtractor={(item, index) => index.toString()}\n        />\n        <View style={styles.addContact}>\n          <button\n            style={styles.button}\n            onPress={() => {\n              this.addContact(\"Jane Smith\", \"jane.smith@example.com\");\n            }}\n          >\n            Add Contact\n          </button>\n        </View>\n      </View>\n    );\n  }\n}\n\nconst styles = StyleSheet.create({\n  container: {\n    flex: 1,\n  },\n  header: {\n    backgroundColor: \"#00AFEF\",\n    paddingTop: 20,\n    paddingBottom: 20\n  },\n  title: {\n    fontSize: 25,\n    textAlign: \"center\"\n  },\n  listItem: {\n    borderBottomWidth: 1,\n    borderBottomColor: \"#ccc\",\n    paddingVertical: 10\n  },\n  buttonContainer: {\n    paddingVertical: 10,\n    flexDirection: \"row\"\n  },\n  button: {\n    backgroundColor: \"#00AFEF\",\n    padding: 10,\n    margin: 10\n  },\n  addContact: {\n    padding: 5,\n    margin: 10\n  }\n});\n\nexport default ContactList;",
