    "input": "",
    "output": "def partition_sets(arr):\n    total_sum = 0\n    for i in arr:\n        total_sum += i\n    half_sum = total_sum // 2\n    dp = [0] * (half_sum + 1)\n\n    for i in arr:\n    \tfor j in range(half_sum, i - 1,-1):\n            dp[j] = max(dp[j], dp[j - i] + i)\n    set1 = dp[half_sum]\n    set2 = total_sum - set1\n    return set1, set2",
