    "instruction": "Create a Flask application with a simple REST API. The API should include endpoints for listing resources, retrieving a single resource, creating a resource, and editing/deleting a resource.",
    "input": "Resource: Books",
    "output": "from flask import Flask, request, jsonify\n\napp = Flask(__name__)\n\nbooks = []\n\n@app.route('/books', methods=['GET', 'POST'])\ndef books_list_create():\n    if request.method == 'GET':\n        return jsonify(books), 200\n \n    data = request.get_json()\n    books.append(data)\n    return jsonify(data), 201\n\n@app.route('/books/<int:book_id>', methods=['GET', 'PUT', 'DELETE'])\ndef book_manipulation(book_id):\n    if request.method == 'GET':\n        book = [book for book in books if book['id'] == book_id]\n        if len(book) == 0:\n            return jsonify({'message': 'Book not found!'}), 404\n        return jsonify(book[0]), 200\n \n    elif request.method == 'PUT':\n        book = [book for book in books if book['id'] == book_id]\n        if len(book) == 0:\n            return jsonify({'message': 'Book not found!'}), 404\n        data = request.get_json()\n        book[0]['title'] = data['title']\n        return jsonify(book[0]), 200\n \n    elif request.method == 'DELETE':\n        book = [book for book in books if book['id'] == book_id]\n        if len(book) == 0:\n            return jsonify({'message': 'Book not found!'}), 404\n        books.remove(book[0])\n        return jsonify({'message': 'Book deleted!'}), 200\n\nif __name__ == \"__main__\":\n    app.run(debug=True)",
