    "output": "def detect_outliers(data):\n    mean = np.mean(data)\n    sd = np.std(data)\n    outliers = []\n    for i in data:\n        z_score = (i - mean) / sd\n        if abs(z_score) > 2:\n            outliers.append(i)\n    return outliers\n\ndata = [1.65, 3, 4.2, 3.3, 9.8, 12.7, 18.3]\noutliers = detect_outliers(data)\nprint(outliers)",
