    "instruction": "Create a function in JavaScript to generate all possible strings of length n using the characters 0, 1, and ?",
    "input": "n = 3",
    "output": "function generateStrings(n) { \n  if (n === 0) { \n    return [\"\"]; \n  } \n  const subResults = generateStrings(n - 1); \n  const result = []; \n  for (var subResult of subResults) { \n    for (let i = 0; i < 3; i++) { \n      let char; \n      if (i === 0) { \n        char = \"0\"; \n      } else if ( i === 1) { \n        char = \"1\"; \n      } else { \n        char = \"?\"; \n      }\n      const str = subResult + char; \n      result.push(str); \n    } \n  } \n  return result; \n\n}",
