    "instruction": "Optimize a decision tree model and find the most important features for the decision tree.",
    "input": "Sample dataset containing reviews for restaurants",
    "output": "#Import the necessary libraries\nfrom sklearn.tree import DecisionTreeClassifier\nfrom sklearn.model_selection import train_test_split\nfrom sklearn.metrics import accuracy_score, precision_score, recall_score\n\n# Load the dataset\ndf = pd.read_csv('data.csv')\n\n# Split the dataset into features and target\nX = df.drop(['rating'], axis = 1)\nY = df['rating']\n\n# Split the dataset into training and test sets\nX_train, X_test, Y_train, Y_test = train_test_split(X, Y, test_size = 0.2, random_state = 0)\n\n# Create the decision tree model\nmodel = DecisionTreeClassifier()\nmodel.fit(X_train,Y_train)\n\n# Make predictions on the test set\nY_pred = model.predict(X_test)\n\n# Calculate the accuracy, precision and recall scores\naccuracy = accuracy_score(Y_test, Y_pred)\nprecision = precision_score(Y_test, Y_pred)\nrecall = recall_score(Y_test, Y_pred)\n\n# Print the scores\nprint('Accuracy: ', accuracy)\nprint('Precision: ', precision)\nprint('Recall: ', recall)\n\n# Optimize the decision tree model\n# Set the max features to consider when looking for the best split\nmodel.max_features = 5\n\n# Fit and predict using the optimized model\nmodel.fit(X_train,Y_train)\nY_pred = model.predict(X_test)\n\n# Calculate the accuracy, precision and recall scores\naccuracy = accuracy_score(Y_test, Y_pred)\nprecision = precision_score(Y_test, Y_pred)\nrecall = recall_score(Y_test, Y_pred)\n\n# Print the scores\nprint('Accuracy: ', accuracy)\nprint('Precision: ', precision)\nprint('Recall: ', recall)\n\n# Get the feature importances\nimportances = list(model.feature_importances_)\n\n# List the most important features\nfeature_list = list(X_train.columns)\nfeature_imp = [(feature, round(importance,2)) for feature, importance in zip(feature_list, importances)]\n[print('Variable: {:20} Importance: {}'.format(*pair)) for pair in feature_imp]",
    "category": "code_instruction"
