    "output": "import numpy as np\n\ndef linear_regression_with_regularization(X, y, l, m):\n    # Add a column of ones to the X matrix \n    ones = np.ones(shape=(m, 1))\n    X = np.concatenate((ones, X), axis=1)\n    \n    # Calculate the parameters theta with the regularized cost function\n    theta = np.linalg.inv(X.T@X + l*np.identity(n=X.shape[1]))@X.T@y\n    \n    return theta",
