    "instruction": "Construct a linked list from the data given below",
    "input": "[2, 4, 6, 8, 10]",
    "output": "\"\"\"\nConstruct a linked list from the following data\n\"\"\"\n\n# Define a node\nclass Node:\n    def __init__(self, data):\n        self.data = data\n        self.next = None\n\n# Insert node to a linked list\ndef insert(head, data):\n    new_node = Node(data)\n    if head is None:\n        return new_node\n    current = head\n    while current.next:\n        current = current.next\n    current.next = new_node\n    return head\n\n# Build a linked list\ninput_list = [2, 4, 6, 8, 10]\nhead = None\nfor data in input_list:\n    head = insert(head, data)\n\n# Print the linked list\ncurrent = head\nwhile current:\n    print(current.data)\n    current = current.next",
