    "output": "pragma solidity ^0.5.15;\n\ncontract ToDo {\n struct Item {\n string name;\n bool isCompleted;\n }\n\n Item[] public items;\n\n event ItemAdded(\n address _contractAddress,\n uint _id,\n string _name,\n bool _isCompleted\n );\n\n event ItemUpdated(\n address _contractAddress,\n uint _id,\n string _name,\n bool _isCompleted\n );\n\n function addItem(string memory _name) public {\n Item memory item = Item({\n name: _name,\n isCompleted: false\n });\n \n items.push(item);\n\n emit ItemAdded(\n address(this),\n items.length - 1,\n _name,\n false\n );\n }\n\n function updateItem(uint _id, string memory _name, bool _isCompleted)\n public {\n require(_id < items.length);\n\n Item storage item = items[_id];\n \n item.name = _name;\n item.isCompleted = _isCompleted;\n \n emit ItemUpdated(\n address(this),\n _id,\n _name,\n _isCompleted\n );\n }\n}\n\n// Web3 code\nvar Web3 = require('web3');\n\n// Connect to blockchain network\nconst web3 = new Web3(\n new Web3.providers.HttpProvider('http://localhost:8545')\n)\n\n// Get deployed contract instance\nconst ToDo = new web3.eth.Contract(contractABI, contractAddress);\n\n// Execute contract methods\nToDo.methods.addItem('Buy Milk').send({from: accountAddress})\n  .then((tx) => {\n  console.log(`Transaction ${tx.transactionHash}`);\n})\n.catch((error) => {\n  console.log(`Error: ${error}`);\n});\n\nToDo.methods.updateItem(0, 'Buy Bread', true).send({from: accountAddress})\n  .then((tx) => {\n  console.log(`Transaction ${tx.transactionHash}`);\n})\n.catch((error) => {\n  console.log(`Error: ${error}`);\n});",
