    "output": "MainActivity.java\n\npublic class MainActivity extends AppCompatActivity {\n\n // Database helper\n private GroceryDbHelper dbHelper;\n\n @Override\n protected void onCreate(Bundle savedInstanceState) {\n super.onCreate(savedInstanceState);\n setContentView(R.layout.activity_main);\n\n dbHelper = new GroceryDbHelper(this);\n \n // ...\n }\n\n}\n\nGroceryDbHelper.java\n\npublic class GroceryDbHelper extends SQLiteOpenHelper { \n\n // Database Info\n private static final String DATABASE_NAME = \"grocery.db\";\n private static final int DATABASE_VERSION = 2;\n\n public GroceryDbHelper(Context context) {\n super(context, DATABASE_NAME, null, DATABASE_VERSION);\n }\n\n // Called when the database connection is being configured.\n // Configure db parameters, such as db version, db tables etc.\n @Override\n public void onConfigure(SQLiteDatabase db) {\n super.onConfigure(db);\n db.setForeignKeyConstraintsEnabled(true);\n }\n\n // Called when the database is created for the first time.\n @Override\n public void onCreate(SQLiteDatabase db) {\n String CREATE_PRODUCTS_TABLE = \"CREATE TABLE products (\" +\n \"id INTEGER PRIMARY KEY,\" +\n \"name TEXT,\" +\n \"price INTEGER\" +\n \");\";\n String CREATE_ORDERS_TABLE = \"CREATE TABLE orders (\" +\n \"id INTEGER PRIMARY KEY,\" +\n \"product_id INTEGER,\" +\n \"quantity INTEGER,\" +\n \"FOREIGN KEY (product_id) REFERENCES products(id)\" +\n \");\";\n \n db.execSQL(CREATE_PRODUCTS_TABLE);\n db.execSQL(CREATE_ORDERS_TABLE);\n }\n\n // Called when the database needs to be upgraded.\n @Override\n public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {\n if (oldVersion != newVersion) {\n // Simplest implementation is to drop all old tables and recreate them\n db.execSQL(\"DROP TABLE IF EXISTS products\");\n db.execSQL(\"DROP TABLE IF EXISTS orders\");\n onCreate(db);\n }\n }\n\n}",
