    "output": "def find_roots(polynomial):\n    coefficients = []\n    degree = 0\n    for term in polynomial.split(\"+\"):\n        coefficient, degree = term.strip().split(\"x^\")\n        coefficients.append(int(coefficient))\n        degree = int(degree)\n    a,b,c = coefficients\n    d = (b**2)-4*a*c\n    root1 = (-b + d**(1/2))/(2*a)\n    root2 = (-b -d**(1/2))/(2*a)\n    return root1, root2",
