    "input": "[\"hello\",\"hell\",\"heaven\"]",
    "output": "def longestCommonPrefix(strings):\n    if len(strings) == 0:\n        return \"\"\n    \n    shortest_string = strings[0]\n      \n    for string in strings:\n        if len(shortest_string) > len(string):\n            shortest_string = string\n    \n    longest_prefix = \"\"\n    for i in range(len(shortest_string)):\n        character = shortest_string[i]\n        prefix_exists = True\n        for string in strings:\n            if string[i] != character:\n                prefix_exists = False\n                break\n        if not prefix_exists:\n            break\n        longest_prefix += character\n    return longest_prefix",
