    "output": "function rotateRight(arr, steps) {\n const n = arr.length;\n steps = steps % n;\n\n for (let i=0; i<steps; i++) {\n let last = arr[n - 1];\n\n for (let j=n-1; j>0; j--) {\n arr[j] = arr[j-1];\n }\n arr[0] = last;\n }\n return arr;\n}\n\nlet arr = [1,2,3,4,5],\n rotNum = 2;\nconsole.log('Original Array :', arr);\n\nlet result = rotateRight(arr, rotNum);\nconsole.log('Rotated Array :', result);\n// Output : Original Array : [ 1, 2, 3, 4, 5 ]\n//Rotated Array : [ 4, 5, 1, 2, 3 ]",
