    "output": "def search(arr, x): \n    low = 0\n    high = len(arr) - 1\n    mid = 0\n  \n    while low <= high: \n        mid = (high + low) // 2\n  \n        if arr[mid] < x: \n            low = mid + 1\n  \n        elif arr[mid] > x: \n            high = mid - 1\n  \n        else: \n            return mid \n  \n    return -1\n\narr = [2, 5, 10, 15, 20] \nx = 15\n\n# Output: 3 \nprint(search(arr, x))",
