    "output": "def is_palindrome(string):\n    string = string.lower()\n    left_pos = 0\n    right_pos = len(string) - 1\n \n    while right_pos >= left_pos:\n        if not string[left_pos] == string[right_pos]:\n            return False\n        left_pos += 1\n        right_pos -= 1\n    return True",
