    "instruction": "Implement a basic spell checker that corrects the spelling errors in a text.",
    "input": "text = \"The quick braown fox jumps over the layzy dog\"",
    "output": "def spell_checker(text):\n    words_list = text.split()\n    correct_list = []\n    for word in words_list:\n        correct_word = \"\"\n        for i in range(len(word)):\n            if word[i].islower():\n                correct_word+=word[i]\n            elif word[i].isupper():\n                correct_word+=(word[i].lower())\n            elif word[i] == 'a':\n                correct_word+='a'\n            elif word[i] == 'e':\n                correct_word+='e'\n            elif word[i] == 'i':\n                correct_word+='i'\n            elif word[i] == 'o':\n                correct_word+='o'\n            elif word[i] == 'u':\n                correct_word+='u'\n        correct_list.append(correct_word)\n    return ' '.join(correct_list)\n\ntext = \"The quick braown fox jumps over the layzy dog\"\nprint(spell_checker(text))",
