    "input": "",
    "output": "import string\nimport random\n\ndef genPassword(length):\n    letter_string = string.ascii_lowercase\n    number_string = string.digits\n\n    password = \"\"\n    while not any(i.isdigit() for i in password):\n        while not any(i.islower() for i in password):\n            password = ''.join(random.choice(letter_string + number_string) for _ in range(length))\n    return password\n\nresult = genPassword(8)\nprint(\"Generated password is\", result)",
