    "output": "import java.util.Random;\n \npublic class NeuralNetwork {\n \n    int input_nodes;\n    int hidden_nodes;\n    int output_nodes;\n    double[][] weights_input_hidden;\n    double[][] weights_hidden_output;\n \n    Random randomGenerator;\n \n    public NeuralNetwork(int input_nodes, int hidden_nodes, int output_nodes){\n        this.input_nodes = input_nodes;\n        this.hidden_nodes = hidden_nodes;\n        this.output_nodes = output_nodes;\n \n        weights_input_hidden = new double[input_nodes+1][hidden_nodes+1];\n        weights_hidden_output = new double[hidden_nodes+1][output_nodes+1];\n        \n        randomGenerator = new Random();\n        randomizeWeights();\n    }\n \n    public void randomizeWeights()\n    {\n        for(int i=0; i<input_nodes+1; i++){\n            for(int j=0; j<hidden_nodes+1; j++){\n                weights_input_hidden[i][j] = randomGenerator.nextDouble()-0.5;\n            }\n        }\n        for(int i=0; i<hidden_nodes+1; i++){\n            for(int j=0; j<output_nodes+1; j++){\n                weights_hidden_output[i][j] = randomGenerator.nextDouble()-0.5;\n            }\n        }\n    }\n \n    // code for the rest of the neural network....\n}",
