    "input": "Data has 10 predictive features and a target column",
    "output": "import numpy as np\nfrom sklearn.feature_selection import f_regression\n\ndef select_features(X, y):\n# calculate importance of each feature\n\tscores, pvalues = f_regression(X, y)\n# add feature names and importance values to a dictionary\n\tfeatures = {}\n\tfor i in range(len(X[0])):\n\t\tfeatures[X.columns[i]] = scores[i]\n# sort the dictionary by importance\n\tselected_features = {k: v for k, v in sorted(features.items(), key=lambda item: item[1], reverse=True)}\n# return top k features\n\treturn list(selected_features.keys())[:k]",
