    "instruction": "Create a Node.js API for a blogging platform. This API should include endpoints for creating, viewing, updating, and deleting blog posts.",
    "input": "Not applicable",
    "output": "const express = require('express');\nconst bodyParser = require('body-parser');\n\nconst app = express();\napp.use(bodyParser.json());\napp.use(bodyParser.urlencoded({ extended: true }));\n\nlet blogPosts = [\n{\n id: 1,\n title: 'My First Blog Post',\n body: 'This is the body of the first blog post.'\n},\n{\n id: 2,\n title: 'My Second Blog Post',\n body: 'This is the body of the second blog post.'\n}\n];\n\n// Create a new blog post\napp.post('/posts', (req, res) => {\n const { title, body } = req.body;\n \n const newPost = {\n id: blogPosts.length + 1,\n title,\n body\n };\n\n blogPosts.push(newPost);\n res.status(201).send(newPost);\n});\n\n// View all blog posts\napp.get('/posts', (req, res) => {\n res.status(200).send(blogPosts);\n});\n\n// Update an existing blog post\napp.put('/posts/:id', (req, res) => {\n const postId = req.params.id;\n const { title, body } = req.body;\n \n const postIndex = blogPosts.findIndex(post => post.id == postId);\n if (postIndex == -1) {\n return res.status(404).send({\n message: 'The post was not found'\n });\n }\n \n blogPosts[postIndex] = {\n ...blogPosts[postIndex],\n title,\n body\n };\n\n return res.status(200).send({ \n message: 'Post updated!',\n post: blogPosts[postIndex]\n });\n});\n\n// Delete an existing blog post\napp.delete('/posts/:id', (req, res) => {\n const postId = req.params.id;\n\n const postIndex = blogPosts.findIndex(post => post.id == postId);\n if (postIndex == -1) {\n return res.status(404).send({\n message: 'The post was not found'\n});\n}\n\nblogPosts = blogPosts.filter(post => post.id !== postId);\n\nreturn res.status(200).send({\n message: 'Post deleted!'\n });\n});\n\nconst PORT = 8000;\napp.listen(PORT, () => {\n console.log(`API server running at http://localhost:${PORT}`);\n});",
    "category": "code_instruction"
