    "instruction": "Generate a C++ code to print all possible arrangements of a given set of numbers.",
    "input": "Set of numbers: [1,2,3]",
    "output": "#include<iostream>\nusing namespace std;\n\nvoid printArrangement(int arr[], int start, int end) {\n    if (start == end) {\n        cout << \"[\";\n        for (int i = 0; i < end; i++) {\n            cout << arr[i] << \" \";\n        }\n        cout << \"]\" << endl;\n    }\n    else {\n        for (int i = start; i < end; i++) {\n            swap(arr[start],arr[i]);\n            printArrangement(arr,start+1,end);\n            swap(arr[start],arr[i]);\n        }\n    }\n}\n\nint main() { \n   int arr[]= {1,2,3};\n   int n = sizeof(arr)/ sizeof(arr[0]);\n   printArrangement(arr,0,n);\n   return 0;\n}",
