    "input": "Message = \"This is a test\"\nKey = 5",
    "output": "def caesarEncrypt(mesg, key):\n encMsg = \"\"\n for char in mesg:\n if char.isalpha():\n num = ord(char)\n num += key\n \n if char.isupper():\n if num > ord('Z'):\n num -= 26\n elif num < ord('A'):\n num += 26\n elif char.islower():\n if num > ord('z'):\n num -= 26\n elif num < ord('a'):\n num += 26\n \n encMsg += chr(num)\n else:\n encMsg += char\n \n return encMsg\n \ndef caesarDecrypt(encMsg, key):\n decMsg = \"\"\n for char in encMsg:\n if char.isalpha():\n num = ord(char)\n num -= key\n \n if char.isupper():\n if num > ord('Z'):\n num -= 26\n elif num < ord('A'):\n num += 26\n elif char.islower():\n if num > ord('z'):\n num -= 26\n elif num < ord('a'):\n num += 26\n \n decMsg += chr(num)\n else:\n decMsg += char\n \n return decMsg\n \nmessage = \"This is a test\"\nkey= 5\n \nencryptedMessage = caesarEncrypt(message, key)\nprint(\"Encrypted Message = \", encryptedMessage)\n \ndecryptedMessage = caesarDecrypt(encryptedMessage, key)\nprint(\"Decrypted Message = \", decryptedMessage)",
