    "output": "const express = require('express');\nconst session = require('express-session');\nconst sqlite3 = require('sqlite3').verbose();\n\nlet app = express();\n\nlet db = new sqlite3.Database('db.sqlite');\n \n// Create table\ndb.run(\"CREATE TABLE IF NOT EXISTS data (key TEXT, value TEXT)\");\n \n// Create route for GET request to retrieve data from the database\napp.get('/data', function (req, res) {\n let sql = \"SELECT * FROM data\";\n db.all(sql, [], (err, rows) => {\n  if (err) {\n   throw err;\n  }\n  res.send(rows);\n });\n});\n \n// Create route for POST request to store data to the database\napp.post('/data', function (req, res) {\n let data = req.body;\n let key = data.key;\n let value = data.value;\n let sql = \"INSERT INTO data (key, value) VALUES (?, ?)\";\n db.run(sql, [key, value], function (err) {\n  if (err) {\n   throw err;\n  }\n  res.send('Data stored to database');\n });\n});\n \n// Start the server\napp.listen(3000, () => {\n  console.log(\"Server is running\");\n});",
