    "instruction": "Optimize the following sorting algorithm.",
    "input": "",
    "output": "def sort(arr):\n    for i in range(len(arr)):\n        min_idx = i\n        for j in range(i+1, len(arr)):\n            if arr[min_idx] > arr[j]:\n                min_idx = j\n        arr[i], arr[min_idx] = arr[min_idx], arr[i]\n\ndef sort_opt(arr):\n    # Select first elements as the sorted part\n    sorted_part_idx = 0\n \n    while sorted_part_idx < len(arr):\n        min_idx = sorted_part_idx\n        for i in range(sorted_part_idx + 1, len(arr)):\n            if arr[min_idx] > arr[i]:\n                min_idx = i\n        arr[sorted_part_idx], arr[min_idx] = arr[min_idx], arr[sorted_part_idx]\n        sorted_part_idx += 1",
    "category": "code_instruction"
