    "output": "int containsDuplicates(int arr[], int n, int k) \n{ \n    unordered_set<int> hash; \n  \n    for (int i = 0; i < n; i++) { \n        if (hash.find(arr[i]) != hash.end()) \n            return 1; \n  \n        hash.insert(arr[i]); \n  \n        if (i >= k) \n            hash.erase(arr[i - k]); \n    } \n  \n    return 0; \n}",
