    "input": "[[1, 3], [2, 4], [5, 6], [7, 9]]",
    "output": "def maximumOverlap(intervals):\n    if (len(intervals) == 0): \n        return 0\n  \n    intervals.sort(key = lambda x: x[0]) \n  \n    result = 1\n    curr_end = intervals[0][1] \n  \n    for index in range(1, len(intervals)): \n        if (intervals[index][0] <= curr_end): \n          \n            curr_end = min(intervals[index][1], curr_end) \n        else: \n            result += 1\n            curr_end = intervals[index][1] \n  \n    return result",
